#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use PDF::API2::Basic::Date;

# Specify the path to the PDF file
my $pdf_file = 'path/to/your/pdf/file.pdf';

# Create a new PDF::API2 object
my $pdf = PDF::API2->open($pdf_file);

# Get the first page of the PDF
my $page = $pdf->open_page(1);

# Extract text from the page
my $text = $page->text;

# Print the text to the console
print "Extracted text from the PDF:\n$text\n";

# Extract metadata from the PDF
my $info = $pdf->info;

# Extract author and creation date from the metadata
my $author = $info->author;
my $creation_date = $info->creation;

# Convert the creation date to a more readable format
if (defined $creation_date) {
    $creation_date = PDF::API2::Basic::Date->new($creation_date)->iso8601;
}

# Print the author and creation date
print "Author: $author\n";
print "Creation Date: $creation_date\n";

# Close the PDF::API2 object
$pdf->end;
```

